void main() {
  for (int i = 0; i < 5; i++) {
    print('Iteration: $i');
  }
}

void main() {
  List<String> names = ['Alice', 'Bob', 'Charlie'];

  for (var name in names) {
    print('Hello, $name');
  }
}

void main() {
  int count = 0;

  while (count < 3) {
    print('Count: $count');
    count++;
  }
}

void main() {
  int number = 5;

  do {
    print('Number is $number');
    number--;
  } while (number > 0);
}

void main() {
  var numbers = [1, 2, 3, 4, 5];

  numbers.forEach((num) {
    print('Square of $num is ${num * num}');
  });
}

void main() {
  for (int i = 0; i < 10; i++) {
    if (i == 5) break;        // exit loop when i is 5
    if (i % 2 == 0) continue; // skip even numbers
    print(i);
  }
}

void main() {
  outerLoop: for (int i = 0; i < 3; i++) {
    for (int j = 0; j < 3; j++) {
      if (i == 1 && j == 1) break outerLoop;
      print('i = $i, j = $j');
    }
  }
}

void main() {
  int sum = 0;
  for (int i = 1; i <= 10; i++) {
    sum += i;
  }
  print('Sum of 1 to 10 is $sum'); // 55
}

void main() {
  Map<String, int> ages = {'Alice': 30, 'Bob': 25, 'Charlie': 35};

  ages.forEach((name, age) {
    print('$name is $age years old');
  });
}

bool isPrime(int n) {
  if (n <= 1) return false;
  for (int i = 2; i <= n ~/ 2; i++) {
    if (n % i == 0) return false;
  }
  return true;
}

void main() {
  for (int i = 2; i <= 20; i++) {
    if (isPrime(i)) {
      print('$i is prime');
    }
  }
}

